/* ─────────────────────────────────────────────
   QR CODE — generated client-side via qrcode lib
   Target: https://www.instagram.com/saynomore.mv
   ───────────────────────────────────────────── */
const QR_URL = "https://www.instagram.com/saynomore.mv";

export function SnmQrCode({ size = 64 }: { size?: number }) {
  const [dataUrl, setDataUrl] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    import("qrcode").then((QRCode) => {
      QRCode.toDataURL(QR_URL, {
        width: size * 2,          // 2× for crisp print rendering
        margin: 1,
        color: { dark: "#000000", light: "#ffffff" },
        errorCorrectionLevel: "M",
      }).then((url) => {
        if (!cancelled) setDataUrl(url);
      });
    });
    return () => { cancelled = true; };
  }, [size]);

  if (!dataUrl) {
    // Tiny placeholder while generating (< 1 frame)
    return <div style={{ width: size, height: size, background: "#f0f0f0" }} />;
  }

  return (
    // eslint-disable-next-line @next/next/no-img-element
    <img
      src={dataUrl}
      alt="QR — instagram.com/saynomore.mv"
      width={size}
      height={size}
      style={{ display: "block", imageRendering: "pixelated" }}
    />
  );
}

